import org.owasp.encoder.Encode;

public class XSSFixedCode {
    public static void main(String[] args) {
        // Simulating user input
        String userInput = "<script>alert('XSS attack!')</script>";

        // Properly handle user input by encoding it before including it in the output
        String sanitizedUserInput = Encode.forHtml(userInput);
        String output = "Welcome, " + sanitizedUserInput;

        System.out.println(output);
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
